using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.Json;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var openAiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// --- Tools ---
var notebook = new Notebook();
var webSearch = new WebSearchService();

var tools = new[]
{
    AIFunctionFactory.Create(webSearch.SearchWeb),
    AIFunctionFactory.Create(webSearch.FetchPage),
    AIFunctionFactory.Create(notebook.AddNote),
    AIFunctionFactory.Create(notebook.GetNotes),
    AIFunctionFactory.Create(notebook.ClearNotes),
};

// --- Chat client with automatic function invocation ---
IChatClient client = new OpenAIClient(openAiKey)
    .GetChatClient(model)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

var chatOptions = new ChatOptions { Tools = [.. tools] };

var systemPrompt = """
    You are a research agent. Your job is to research a topic the user provides.

    Workflow:
    1. Search the web for information on the topic.
    2. Fetch promising pages to read their content.
    3. Take notes on key findings using the note-taking tool.
    4. When you have gathered enough information, retrieve all your notes and
       produce a well-structured summary with citations.

    Guidelines:
    - Perform multiple searches with different queries to get broad coverage.
    - Always take notes before summarizing so nothing is lost.
    - Cite sources by URL when possible.
    - Be thorough but concise in your final summary.
    """;

// --- Main loop ---
Console.WriteLine("🔬 Research Agent Ready");
Console.WriteLine("Enter a topic to research (or 'quit' to exit):\n");

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("> ");
    Console.ResetColor();

    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    notebook.ClearNotesInternal();

    var messages = new List<ChatMessage>
    {
        new(ChatRole.System, systemPrompt),
        new(ChatRole.User, $"Research the following topic and provide a summary: {topic}"),
    };

    Console.ForegroundColor = ConsoleColor.Yellow;
    Console.WriteLine("\n⏳ Researching… (the agent will search the web and take notes)\n");
    Console.ResetColor();

    var response = await client.GetResponseAsync(messages, chatOptions);

    Console.ForegroundColor = ConsoleColor.Green;
    Console.WriteLine("── Research Summary ─────────────────────────────────");
    Console.ResetColor();
    Console.WriteLine(response.Text);
    Console.WriteLine("─────────────────────────────────────────────────────\n");
}

Console.WriteLine("Goodbye!");

