/// <summary>Provides web search and page-fetching capabilities.</summary>
sealed class WebSearchService
{
    private static readonly HttpClient Http = new()
    {
        DefaultRequestHeaders =
        {
            { "User-Agent", "Mozilla/5.0 (compatible; ResearchAgent/1.0)" }
        },
        Timeout = TimeSpan.FromSeconds(15),
    };

    [Description("Search the web for a query and return a list of result titles, snippets, and URLs.")]
    public async Task<string> SearchWeb(
        [Description("The search query string")] string query)
    {
        Console.ForegroundColor = ConsoleColor.DarkGray;
        Console.WriteLine($"  🔍 Searching: \"{query}\"");
        Console.ResetColor();

        try
        {
            var encoded = WebUtility.UrlEncode(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";
            var html = await Http.GetStringAsync(url);

            var results = ParseDuckDuckGoResults(html);
            if (results.Count == 0)
                return "No results found.";

            return JsonSerializer.Serialize(results, new JsonSerializerOptions { WriteIndented = true });
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Fetch the text content of a web page given its URL. Returns the first ~4000 characters of readable text.")]
    public async Task<string> FetchPage(
        [Description("The full URL of the page to fetch")] string url)
    {
        Console.ForegroundColor = ConsoleColor.DarkGray;
        Console.WriteLine($"  🌐 Fetching: {url}");
        Console.ResetColor();

        try
        {
            var html = await Http.GetStringAsync(url);
            var text = StripHtml(html);
            return text.Length > 4000 ? text[..4000] + "\n[…truncated]" : text;
        }
        catch (Exception ex)
        {
            return $"Fetch failed: {ex.Message}";
        }
    }

    private static List<SearchResult> ParseDuckDuckGoResults(string html)
    {
        var results = new List<SearchResult>();
        var linkPattern = new Regex(
            @"<a[^>]+class=""result__a""[^>]*href=""([^""]+)""[^>]*>(.*?)</a>",
            RegexOptions.Singleline | RegexOptions.IgnoreCase);
        var snippetPattern = new Regex(
            @"<a[^>]+class=""result__snippet""[^>]*>(.*?)</a>",
            RegexOptions.Singleline | RegexOptions.IgnoreCase);

        var links = linkPattern.Matches(html);
        var snippets = snippetPattern.Matches(html);

        for (int i = 0; i < Math.Min(links.Count, 8); i++)
        {
            var rawUrl = WebUtility.HtmlDecode(links[i].Groups[1].Value);
            // DuckDuckGo wraps URLs in a redirect; extract the actual URL.
            var actualUrl = ExtractRedirectUrl(rawUrl);
            var title = StripHtmlTags(links[i].Groups[2].Value).Trim();
            var snippet = i < snippets.Count
                ? StripHtmlTags(snippets[i].Groups[1].Value).Trim()
                : "";

            if (!string.IsNullOrEmpty(title))
                results.Add(new(title, snippet, actualUrl));
        }

        return results;
    }

    private static string ExtractRedirectUrl(string url)
    {
        // DuckDuckGo uses //duckduckgo.com/l/?uddg=<encoded_url>&...
        if (url.Contains("uddg="))
        {
            var match = Regex.Match(url, @"uddg=([^&]+)");
            if (match.Success)
                return WebUtility.UrlDecode(match.Groups[1].Value);
        }
        return url;
    }

    private static string StripHtmlTags(string html) =>
        Regex.Replace(html, "<[^>]+>", "");

    private static string StripHtml(string html)
    {
        // Remove script/style blocks, then tags, then collapse whitespace.
        var cleaned = Regex.Replace(html, @"<(script|style)[^>]*>.*?</\1>", "",
            RegexOptions.Singleline | RegexOptions.IgnoreCase);
        cleaned = Regex.Replace(cleaned, "<[^>]+>", " ");
        cleaned = WebUtility.HtmlDecode(cleaned);
        cleaned = Regex.Replace(cleaned, @"\s+", " ").Trim();
        return cleaned;
    }

    private record SearchResult(string Title, string Snippet, string Url);
}

/// <summary>In-memory notebook for the agent to store research notes.</summary>
sealed class Notebook
{
    private readonly List<string> _notes = [];

    [Description("Save a research note. Use this to record key findings, facts, or quotes with their source URL.")]
    public string AddNote(
        [Description("The note content to save, ideally including the source URL")] string note)
    {
        _notes.Add(note);
        Console.ForegroundColor = ConsoleColor.DarkGray;
        Console.WriteLine($"  📝 Note #{_notes.Count} saved");
        Console.ResetColor();
        return $"Note #{_notes.Count} saved.";
    }

    [Description("Retrieve all saved research notes.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        for (int i = 0; i < _notes.Count; i++)
            sb.AppendLine($"[Note {i + 1}] {_notes[i]}");
        return sb.ToString();
    }

    [Description("Clear all saved notes to start fresh.")]
    public string ClearNotes()
    {
        ClearNotesInternal();
        return "All notes cleared.";
    }

    internal void ClearNotesInternal() => _notes.Clear();
}

